module counter_4bit(
    input clk,
    input en,
    input reset,
    output reg [3:0] count
    );

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or posedge dbg_halt)
    begin
        if (reset)
            count <= 4'b0000;
        else if (en)
            count <= count + 1;
    end
endmodule
